sql:
SELECT COUNT(*) AS num_states
FROM gun_laws
WHERE concealed_carry = 1;

SELECT states.state_name, gun_safety_grades.grade
FROM states
JOIN gun_safety_grades ON states.state_id = gun_safety_grades.state_id;

SELECT gsg.grade_id, gsg.state_id, gsg.grade, gsg.grade_date, s.state_name
FROM gun_safety_grades AS gsg
JOIN states AS s ON gsg.state_id = s.state_id;

SELECT s.state_name, COALESCE(gl.high_capacity_magazine_ban, 'Not given') AS high_capacity_magazine_ban
FROM states s
JOIN gun_laws gl ON s.state_id = gl.state_id;

SELECT states.state_name, gun_laws.background_checks
FROM states
INNER JOIN gun_laws ON states.state_id = gun_laws.state_id;

external_knowledge:
Partial background checks refer to the practice of conducting background checks on some, but not all, individuals before allowing them to purchase firearms.
Gun safety grades (A-F) are a measure of the stringency of a state's gun laws; 
'Partial' background checks indicate that a state does not require background checks for all types of firearm sales or transfers.

